'use server'

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'
import { orderSchema, OrderFormValues } from '@/lib/validations/product-order'
import { z } from 'zod'

/**
 * Helper to upsert master data (client, product, client_product)
 */
async function upsertMasterItem(
    supabase: any,
    table: string,
    nameColumn: string,
    nameValue: string,
    additionalData: any = {}
) {
    const normalizedName = nameValue.trim().toUpperCase();
    if (!normalizedName) return { id: null, isNew: false };

    // 1. Try to find existing
    let query = supabase.from(table).select('id').eq(nameColumn, normalizedName);

    // Support composite unique(client_id, name) for client_products
    if (additionalData.client_id && table === 'client_products') {
        query = query.eq('client_id', additionalData.client_id);
    }

    const { data: existing } = await query.maybeSingle();

    if (existing) {
        return { id: existing.id, isNew: false };
    }

    // 2. Insert new if not found
    const { data: inserted, error } = await supabase
        .from(table)
        .insert({ [nameColumn]: normalizedName, ...additionalData })
        .select('id')
        .single();

    if (error) {
        // Handle race condition
        let retryQuery = supabase.from(table).select('id').eq(nameColumn, normalizedName);
        if (additionalData.client_id && table === 'client_products') {
            retryQuery = retryQuery.eq('client_id', additionalData.client_id);
        }
        const { data: retry } = await retryQuery.maybeSingle();

        if (retry) return { id: retry.id, isNew: false };
        throw error;
    }

    return { id: inserted.id, isNew: true };
}

export async function addOrder(data: OrderFormValues) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
        return { success: false, error: '?몄쬆?섏? ?딆? ?ъ슜?먯엯?덈떎.' }
    }

    // 1. Zod Validation
    const result = orderSchema.safeParse(data)
    if (!result.success) {
        return {
            success: false,
            error: '?낅젰媛믪씠 ?щ컮瑜댁? ?딆뒿?덈떎.',
            details: result.error.flatten().fieldErrors
        }
    }

    const newMasterItems: string[] = [];

    try {
        // 2. UPSERT Master Data: Client
        const { id: clientId, isNew: isNewClient } = await upsertMasterItem(
            supabase,
            'clients',
            'company_name',
            result.data.client_name
        );
        if (isNewClient) newMasterItems.push(`怨좉컼?? ${result.data.client_name}`);

        // 3. Calculate Total Amount
        const total_amount = result.data.items.reduce((sum: number, item: any) => sum + (item.quantity * item.unit_price), 0)

        // 4. Insert Master Record (Order)
        const { data: orderData, error: orderError } = await supabase
            .from('orders')
            .insert({
                client_id: clientId,
                sales_person_id: user.id,
                due_date: result.data.due_date ? result.data.due_date.toISOString() : null,
                total_amount: total_amount,
                memo: result.data.memo?.trim() || null,
                status: 'draft' // Initial state
            })
            .select('id')
            .single()

        if (orderError || !orderData) {
            console.error('Order Insert error:', orderError)
            return { success: false, error: '?섏＜ 留덉뒪???앹꽦???ㅽ뙣?덉뒿?덈떎.' }
        }

        // 5. Process Order Items (UPSERT Products each)
        const orderItemsToInsert = [];

        for (const item of result.data.items) {
            // Upsert Product
            const { id: productId, isNew: isNewProd } = await upsertMasterItem(
                supabase,
                'products',
                'name',
                item.product_name,
                { price: item.unit_price, category: 'bottle' } // Optional initial price & default category
            );
            if (isNewProd) newMasterItems.push(`?쒗뭹: ${item.product_name}`);

            // Upsert Client Product if provided
            let clientProductId = null;
            if (item.client_product_name && clientId) {
                const { id: cpId, isNew: isNewCP } = await upsertMasterItem(
                    supabase,
                    'client_products',
                    'name',
                    item.client_product_name,
                    { client_id: clientId }
                );
                clientProductId = cpId;
                if (isNewCP) newMasterItems.push(`怨좉컼???쒗뭹: ${item.client_product_name}`);
            }

            orderItemsToInsert.push({
                order_id: orderData.id,
                product_id: productId,
                client_product_id: clientProductId,
                quantity: item.quantity,
                unit_price: item.unit_price,
                subtotal: item.quantity * item.unit_price
            });
        }

        // 6. Insert Detail Records (Order Items)
        const { error: itemsError } = await supabase
            .from('order_items')
            .insert(orderItemsToInsert)

        if (itemsError) {
            console.error('Order Items Insert error:', itemsError)
            // Rollback master
            await supabase.from('orders').delete().eq('id', orderData.id)
            return { success: false, error: '?섏＜ ?곸꽭 ??ぉ ??μ뿉 ?ㅽ뙣?덉뒿?덈떎.' }
        }

        revalidatePath('/dashboard/sales/order')
        revalidatePath('/dashboard/sales/activity')
        revalidatePath('/dashboard/sales/planning')
        return {
            success: true,
            newMasterItems: newMasterItems.length > 0 ? newMasterItems : undefined
        }

    } catch (error) {
        console.error('Server action error:', error)
        return {
            success: false,
            error: '?쒕쾭 ?ㅻ쪟媛 諛쒖깮?덉뒿?덈떎.'
        }
    }
}

'use server'

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'

export async function saveOrderDetails(orderId: string, poNumber: string) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) {
        return { success: false, error: '?몄쬆?섏? ?딆? ?ъ슜?먯엯?덈떎.' }
    }

    try {
        // [PO 以묐났 諛⑹뼱] Application level check
        const { count } = await supabase
            .from('orders')
            .select('*', { count: 'exact', head: true })
            .eq('po_number', poNumber)
            .neq('id', orderId)

        if (count && count > 0) {
            return { success: false, error: '?대? ?깅줉??諛쒖＜ 踰덊샇?낅땲??' }
        }

        const { error } = await supabase
            .from('orders')
            .update({ po_number: poNumber } as any)
            .eq('id', orderId)

        if (error) {
            if (error.code === '23505') { // Unique violation code in Postgres
                return { success: false, error: '?대? ?깅줉??諛쒖＜ 踰덊샇?낅땲??' }
            }
            console.error('saveOrderDetails error:', error)
            return { success: false, error: '諛쒖＜ ?뺣낫 ?낅뜲?댄듃???ㅽ뙣?덉뒿?덈떎.' }
        }

        revalidatePath('/dashboard/sales/order')
        return { success: true }
    } catch (error) {
        console.error('saveOrderDetails exception:', error)
        return { success: false, error: '?쒕쾭 ?ㅻ쪟媛 諛쒖깮?덉뒿?덈떎.' }
    }
}

